class BankAccount {
public:
    BankAccount(int id, double balance) : id(id), balance(balance) {}

    void deposit(double amount) {
        std::lock_guard<std::mutex> lock(mutex);
        balance += amount;
    }

    void withdraw(double amount) {
        std::lock_guard<std::mutex> lock(mutex);
        if (balance >= amount) {
            balance -= amount;
        } else {
            std::cout << "Insufficient funds for account " << id << std::endl;
        }
    }

    double getBalance() {
        std::lock_guard<std::mutex> lock(mutex);
        return balance;
    }

private:
    int id;
    double balance;
    std::mutex mutex;
};

class Bank {
public:
    void addAccount(int id, double balance) {
        std::lock_guard<std::mutex> lock(mutex);
        accounts[id] = BankAccount(id, balance);
    }

    BankAccount* getAccount(int id) {
        std::lock_guard<std::mutex> lock(mutex);
        return &accounts[id];
    }

private:
    std::unordered_map<int, BankAccount> accounts;
    std::mutex mutex;
};

void transaction(Bank& bank, int accountId, double amount, bool isDeposit) {
    BankAccount* account = bank.getAccount(accountId);
    if (isDeposit) {
        account->deposit(amount);
    } else {
        account->withdraw(amount);
    }
}

